mapper.select:
select a.id AS id, a.channelCode , a.channelName , a.customerType , a.channelAddr, a.remark , a.status , a.updatedTime, a.updaterName, a.chooseFlag, a.channelTotal from ( SELECT t.id AS id, t.channel_code AS channelCode, t.channel_name AS channelName, t.customer_type AS customerType, t.channel_addr AS channelAddr, t.remark AS remark, t.status AS status,
CASE WHEN t1.created_time IS NOT NULL THEN t1.created_time ELSE t.updated_time END AS updatedTime,
CASE WHEN t1.creator IS NOT NULL THEN t1.creator ELSE t.creator_name END AS updaterName,
CASE WHEN t.channel_code = t1.channel_code THEN 1 ELSE 0 END AS chooseFlag, (SELECT COUNT(1) FROM customer_channel cc WHERE cc.channel_code = t1.channel_code) AS channelTotal
FROM customer_channel t LEFT JOIN site_customer t1 ON t.channel_code = t1.channel_code AND t1.site_code = #{vo.siteCode}
AND t.channel_name = #{vo.channelName}
AND t.channel_code = #{vo.channelCode}
) a ORDER BY a.channelTotal desc ,a.status DESC, a.updatedTime DESC
